INSERT INTO examples (name, category, framework, files, dependencies, metadata) VALUES ('"image-gallery-with-vertical-scroll"', '"Stateful"', '"vanilla"', '{"demo.css": ".gallery-container {\n  display: flex;\n  justify-content: center;\n}\n\n.thumbnails {\n  display: flex;\n  flex-direction: column;\n  gap: 8px;\n}\n\n.thumbnails img {\n  width: 40px;\n  height: 40px;\n  cursor: pointer;\n}\n\n.scrollbar {\n  width: 1px;\n  height: 720px;\n  background: #ccc;\n  display: block;\n  margin: 0 0 0 8px;\n}\n\n.thumb {\n  width: 1px;\n  position: absolute;\n  height: 0;\n  background: #000;\n}\n\n.slides {\n  margin: 0 16px;\n  display: grid;\n  grid-auto-flow: row;\n  gap: 1rem;\n  width: calc(540px + 1rem);\n  padding: 0 0.25rem;\n  height: 720px;\n  overflow-y: auto;\n  overscroll-behavior-y: contain;\n  scroll-snap-type: y mandatory;\n  scrollbar-width: none;\n}\n\n.slides > div {\n  scroll-snap-align: start;\n}\n\n.slides img {\n  width: 540px;\n  object-fit: contain;\n}\n\n.slides::-webkit-scrollbar {\n  display: none;\n}\n", "demo.html": "<!DOCTYPE html>\r\n<html lang=\"en\">\r\n  <head>\r\n    <meta charset=\"UTF-8\" />\r\n    <meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\" />\r\n    <meta http-equiv=\"X-UA-Compatible\" content=\"ie=edge\" />\r\n    <link rel=\"stylesheet\" href=\"style.css\" />\r\n    <title>Static Template</title>\r\n  </head>\r\n  <body>\r\n    <h1>\r\n      Image Gallery with vertical scroll\r\n    </h1>\r\n    <div class=\"gallery-container\">\r\n      <div class=\"thumbnails\"></div>\r\n      <div class=\"scrollbar\">\r\n        <div class=\"thumb\"></div>\r\n      </div>\r\n      <div class=\"slides\">\r\n        <div><img src=\"https://picsum.photos/id/1067/540/720\" /></div>\r\n        <div><img src=\"https://picsum.photos/id/122/540/720\" /></div>\r\n        <div><img src=\"https://picsum.photos/id/188/540/720\" /></div>\r\n        <div><img src=\"https://picsum.photos/id/249/540/720\" /></div>\r\n        <div><img src=\"https://picsum.photos/id/257/540/720\" /></div>\r\n        <div><img src=\"https://picsum.photos/id/259/540/720\" /></div>\r\n        <div><img src=\"https://picsum.photos/id/283/540/720\" /></div>\r\n        <div><img src=\"https://picsum.photos/id/288/540/720\" /></div>\r\n        <div><img src=\"https://picsum.photos/id/299/540/720\" /></div>\r\n      </div>\r\n    </div>\r\n\r\n    <script src=\"script.js\"></script>\r\n  </body>\r\n</html>\r\n", "demo.js": "const slideGallery = document.querySelector(''.slides'');\nconst slides = slideGallery.querySelectorAll(''div'');\nconst scrollbarThumb = document.querySelector(''.thumb'');\nconst slideCount = slides.length;\nconst slideHeight = 720;\nconst marginTop = 16;\n\nconst scrollThumb = () => {\n  const index = Math.floor(slideGallery.scrollTop / slideHeight);\n  scrollbarThumb.style.height = `${((index + 1) / slideCount) * slideHeight}px`;\n};\n\nconst scrollToElement = el => {\n  const index = parseInt(el.dataset.id, 10);\n  slideGallery.scrollTo(0, index * slideHeight + marginTop);\n};\n\ndocument.querySelector(''.thumbnails'').innerHTML += [...slides]\n  .map(\n    (slide, i) => `<img src=\"${slide.querySelector(''img'').src}\" data-id=\"${i}\">`\n  )\n  .join('''');\n\ndocument.querySelectorAll(''.thumbnails img'').forEach(el => {\n  el.addEventListener(''click'', () => scrollToElement(el));\n});\n\nslideGallery.addEventListener(''scroll'', e => scrollThumb());\n\nscrollThumb();\n"}', '{}', '{"original_path": "Vanilla/Stateful/Layout/image-gallery-with-vertical-scroll"}'), ('"CountdownTimer"', '"display"', '"react"', '{"component/CountDown.jsx": "import React, { useEffect } from \"react\";\r\nconst CountDown = ({ hours = 0, minutes = 0, seconds = 0 }) => {\r\n  const [paused, setPaused] = React.useState(false);\r\n  const [over, setOver] = React.useState(false);\r\n  const [[h, m, s], setTime] = React.useState([hours, minutes, seconds]);\r\n\r\n  const tick = () => {\r\n    if (paused || over) return;\r\n    if (h === 0 && m === 0 && s === 0) setOver(true);\r\n    else if (m === 0 && s === 0) {\r\n      setTime([h - 1, 59, 59]);\r\n    } else if (s == 0) {\r\n      setTime([h, m - 1, 59]);\r\n    } else {\r\n      setTime([h, m, s - 1]);\r\n    }\r\n  };\r\n\r\n  const reset = () => {\r\n    setTime([parseInt(hours), parseInt(minutes), parseInt(seconds)]);\r\n    setPaused(false);\r\n    setOver(false);\r\n  };\r\n\r\n  useEffect(() => {\r\n    const timerID = setInterval(() => tick(), 1000);\r\n    return () => clearInterval(timerID);\r\n  });\r\n\r\n  return (\r\n    <div>\r\n      <p>{`${h.toString().padStart(2, \"0\")}:${m\r\n        .toString()\r\n        .padStart(2, \"0\")}:${s.toString().padStart(2, \"0\")}`}</p>\r\n      <div>{over ? \"Time''s up!\" : \"\"}</div>\r\n      <button onClick={() => setPaused(!paused)}>\r\n        {paused ? \"Resume\" : \"Pause\"}\r\n      </button>\r\n      <button onClick={() => reset()}>Restart</button>\r\n    </div>\r\n  );\r\n};\r\n\r\nexport default CountDown;\r\n", "package.json": "{\n  \"name\": \"stackblitz-starters-rzbtlt\",\n  \"version\": \"0.0.0\",\n  \"private\": true,\n  \"dependencies\": {\n    \"react\": \"18.2.0\",\n    \"react-dom\": \"18.2.0\"\n  },\n  \"scripts\": {\n    \"start\": \"react-scripts start\",\n    \"build\": \"react-scripts build\",\n    \"test\": \"react-scripts test --env=jsdom\",\n    \"eject\": \"react-scripts eject\"\n  },\n  \"devDependencies\": {\n    \"react-scripts\": \"latest\"\n  }\n}", "public/index.html": "<div id=\"app\"></div>", "src/App.js": "import React from ''react'';\nimport CountDown from \"../component/CountDown\";\nimport ''./style.css'';\n\nexport default function App() {\n  return (\n    <div>\n      <h1>Countdown timer</h1>\n      <CountDown hours={1} minutes={45} />\n    </div>\n  );\n}\n", "src/style.css": "* {\n  box-sizing: border-box;\n}\n\nbody {\n  margin: 0;\n  padding: 1rem;\n  font-family: system-ui, sans-serif;\n  color: black;\n  background-color: white;\n}\n\nh1 {\n  font-weight: 800;\n  font-size: 1.5rem;\n}\n"}', '{"react": "18.2.0", "react-dom": "18.2.0"}', '{"original_path": "component/react/display/CountdownTimer"}'), ('"DataList"', '"display"', '"react"', '{"component/DataList.jsx": "const DataList = ({ isOrdered = false, data }) => {\r\n  const list = data.map((val, i) => <li key={`${i}_${val}`}>{val}</li>);\r\n  return isOrdered ? <ol>{list}</ol> : <ul>{list}</ul>;\r\n};\r\n\r\nexport default DataList;\r\n", "package.json": "{\n  \"name\": \"stackblitz-starters-rzbtlt\",\n  \"version\": \"0.0.0\",\n  \"private\": true,\n  \"dependencies\": {\n    \"react\": \"18.2.0\",\n    \"react-dom\": \"18.2.0\"\n  },\n  \"scripts\": {\n    \"start\": \"react-scripts start\",\n    \"build\": \"react-scripts build\",\n    \"test\": \"react-scripts test --env=jsdom\",\n    \"eject\": \"react-scripts eject\"\n  },\n  \"devDependencies\": {\n    \"react-scripts\": \"latest\"\n  }\n}", "public/index.html": "<div id=\"app\"></div>", "src/App.js": "import React from ''react'';\nimport DataList from \"../component/DataList\";\nimport ''./style.css'';\n\nexport default function App() {\n  return (\n    <div className=\"App\">\n      <h1>Data list</h1>\n      <DataList data={names} />\n      <DataList data={names} isOrdered />\n    </div>\n  );\n}\n", "src/style.css": "* {\n  box-sizing: border-box;\n}\n\nbody {\n  margin: 0;\n  padding: 1rem;\n  font-family: system-ui, sans-serif;\n  color: black;\n  background-color: white;\n}\n\nh1 {\n  font-weight: 800;\n  font-size: 1.5rem;\n}\n"}', '{"react": "18.2.0", "react-dom": "18.2.0"}', '{"original_path": "component/react/display/DataList"}'), ('"DataTable"', '"display"', '"react"', '{"component/DataTable.jsx": "const DataTable = ({ data }) => {\r\n  return (\r\n    <table>\r\n      <thead>\r\n        <tr>\r\n          <th>ID</th>\r\n          <th>Value</th>\r\n        </tr>\r\n      </thead>\r\n      <tbody>\r\n        {data.map((val, i) => (\r\n          <tr key={`${i}_${val}`}>\r\n            <td>{i}</td>\r\n            <td>{val}</td>\r\n          </tr>\r\n        ))}\r\n      </tbody>\r\n    </table>\r\n  );\r\n};\r\n\r\nexport default DataTable;\r\n", "package.json": "{\n  \"name\": \"stackblitz-starters-rzbtlt\",\n  \"version\": \"0.0.0\",\n  \"private\": true,\n  \"dependencies\": {\n    \"react\": \"18.2.0\",\n    \"react-dom\": \"18.2.0\"\n  },\n  \"scripts\": {\n    \"start\": \"react-scripts start\",\n    \"build\": \"react-scripts build\",\n    \"test\": \"react-scripts test --env=jsdom\",\n    \"eject\": \"react-scripts eject\"\n  },\n  \"devDependencies\": {\n    \"react-scripts\": \"latest\"\n  }\n}", "public/index.html": "<div id=\"app\"></div>", "src/App.js": "import React from ''react'';\nimport DataTable from \"../component/DataTable\";\nimport ''./style.css'';\n\nexport default function App() {\n  const people = [\"John\", \"Jesse\"];\n\n  return (\n    <div className=\"App\">\n      <h1>Data table</h1>\n      <DataTable data={people} />\n    </div>\n  );\n}\n", "src/style.css": "* {\n  box-sizing: border-box;\n}\n\nbody {\n  margin: 0;\n  padding: 1rem;\n  font-family: system-ui, sans-serif;\n  color: black;\n  background-color: white;\n}\n\nh1 {\n  font-weight: 800;\n  font-size: 1.5rem;\n}\n"}', '{"react": "18.2.0", "react-dom": "18.2.0"}', '{"original_path": "component/react/display/DataTable"}'), ('"LazyLoad"', '"display"', '"react"', '{"component/LazyLoad.jsx": "import React, { useRef } from \"react\";\r\n\r\nconst LazyLoadImage = ({\r\n  alt,\r\n  src,\r\n  className,\r\n  loadInitially = false,\r\n  observerOptions = { root: null, rootMargin: \"200px 0px\" },\r\n  ...props\r\n}) => {\r\n  const observerRef = React.useRef(null);\r\n  const imgRef = React.useRef(null);\r\n  const [isLoaded, setIsLoaded] = React.useState(loadInitially);\r\n\r\n  const observerCallback = React.useCallback(\r\n    (entries) => {\r\n      if (entries[0].isIntersecting) {\r\n        observerRef.current.disconnect();\r\n        setIsLoaded(true);\r\n      }\r\n    },\r\n    [observerRef]\r\n  );\r\n\r\n  React.useEffect(() => {\r\n    if (loadInitially) return;\r\n\r\n    if (\"loading\" in HTMLImageElement.prototype) {\r\n      setIsLoaded(true);\r\n      return;\r\n    }\r\n\r\n    observerRef.current = new IntersectionObserver(\r\n      observerCallback,\r\n      observerOptions\r\n    );\r\n    observerRef.current.observe(imgRef.current);\r\n    return () => {\r\n      observerRef.current.disconnect();\r\n    };\r\n  }, []);\r\n\r\n  return (\r\n    <img\r\n      alt={alt}\r\n      src={isLoaded ? src : \"\"}\r\n      ref={imgRef}\r\n      className={className}\r\n      loading={loadInitially ? undefined : \"lazy\"}\r\n      {...props}\r\n    />\r\n  );\r\n};\r\n\r\nexport default LazyLoadImage;\r\n", "package.json": "{\n  \"name\": \"stackblitz-starters-rzbtlt\",\n  \"version\": \"0.0.0\",\n  \"private\": true,\n  \"dependencies\": {\n    \"react\": \"18.2.0\",\n    \"react-dom\": \"18.2.0\"\n  },\n  \"scripts\": {\n    \"start\": \"react-scripts start\",\n    \"build\": \"react-scripts build\",\n    \"test\": \"react-scripts test --env=jsdom\",\n    \"eject\": \"react-scripts eject\"\n  },\n  \"devDependencies\": {\n    \"react-scripts\": \"latest\"\n  }\n}", "public/index.html": "<div id=\"app\"></div>", "src/App.js": "import React from ''react'';\nimport LazyLoad from \"../component/LazyLoad\"\nimport ''./style.css'';\n\nexport default function App() {\n  return (\n    <div className=\"App\">\n      <h1>Lazy-loading image</h1>\n      <LazyLoadImage\n        src=\"https://picsum.photos/id/1080/600/600\"\n        alt=\"Strawberries\"\n      />\n    </div>\n  );\n}\n", "src/style.css": "* {\n  box-sizing: border-box;\n}\n\nbody {\n  margin: 0;\n  padding: 1rem;\n  font-family: system-ui, sans-serif;\n  color: black;\n  background-color: white;\n}\n\nh1 {\n  font-weight: 800;\n  font-size: 1.5rem;\n}\n"}', '{"react": "18.2.0", "react-dom": "18.2.0"}', '{"original_path": "component/react/display/LazyLoad"}'), ('"MappedTable"', '"display"', '"react"', '{"component/MappedTable.jsx": "const MappedTable = ({ data, propertyNames }) => {\r\n  let filteredData = data.map((v) =>\r\n    Object.keys(v)\r\n      .filter((k) => propertyNames.includes(k))\r\n      .reduce((acc, key) => ((acc[key] = v[key]), acc), {})\r\n  );\r\n  return (\r\n    <table>\r\n      <thead>\r\n        <tr>\r\n          {propertyNames.map((val) => (\r\n            <th key={`h_${val}`}>{val}</th>\r\n          ))}\r\n        </tr>\r\n      </thead>\r\n      <tbody>\r\n        {filteredData.map((val, i) => (\r\n          <tr key={`i_${i}`}>\r\n            {propertyNames.map((p) => (\r\n              <td key={`i_${i}_${p}`}>{val[p]}</td>\r\n            ))}\r\n          </tr>\r\n        ))}\r\n      </tbody>\r\n    </table>\r\n  );\r\n};\r\n\r\nexport default MappedTable;\r\n", "package.json": "{\n  \"name\": \"stackblitz-starters-rzbtlt\",\n  \"version\": \"0.0.0\",\n  \"private\": true,\n  \"dependencies\": {\n    \"react\": \"18.2.0\",\n    \"react-dom\": \"18.2.0\"\n  },\n  \"scripts\": {\n    \"start\": \"react-scripts start\",\n    \"build\": \"react-scripts build\",\n    \"test\": \"react-scripts test --env=jsdom\",\n    \"eject\": \"react-scripts eject\"\n  },\n  \"devDependencies\": {\n    \"react-scripts\": \"latest\"\n  }\n}", "public/index.html": "<div id=\"app\"></div>", "src/App.js": "import React from ''react'';\nimport MappedTable from \"../component/MappedTable\";\nimport ''./style.css'';\n\nexport default function App() {\n  const people = [\n    { name: \"John\", surname: \"Smith\", age: 42 },\n    { name: \"Adam\", surname: \"Smith\", gender: \"male\" }\n  ];\n  const propertyNames = [\"name\", \"surname\", \"age\"];\n\n  return (\n    <div className=\"App\">\n      <h1>Object table view</h1>\n      <MappedTable data={people} propertyNames={propertyNames} />\n    </div>\n  );\n}\n", "src/style.css": "* {\n  box-sizing: border-box;\n}\n\nbody {\n  margin: 0;\n  padding: 1rem;\n  font-family: system-ui, sans-serif;\n  color: black;\n  background-color: white;\n}\n\nh1 {\n  font-weight: 800;\n  font-size: 1.5rem;\n}\n"}', '{"react": "18.2.0", "react-dom": "18.2.0"}', '{"original_path": "component/react/display/MappedTable"}'), ('"ClosableAlert"', '"feedback"', '"react"', '{"component/Alert.jsx": "import React, { useEffect } from \"react\";\r\n\r\nconst Alert = ({ isDefaultShown = false, timeout = 250, type, message }) => {\r\n  const [isShown, setIsShown] = React.useState(isDefaultShown);\r\n  const [isLeaving, setIsLeaving] = React.useState(false);\r\n\r\n  let timeoutId = null;\r\n\r\n  useEffect(() => {\r\n    setIsShown(true);\r\n    return () => {\r\n      clearTimeout(timeoutId);\r\n    };\r\n  }, [isDefaultShown, timeout, timeoutId]);\r\n\r\n  const closeAlert = () => {\r\n    setIsLeaving(true);\r\n    timeoutId = setTimeout(() => {\r\n      setIsLeaving(false);\r\n      setIsShown(false);\r\n    }, timeout);\r\n  };\r\n\r\n  return (\r\n    isShown && (\r\n      <div\r\n        className={`alert ${type} ${isLeaving ? \"leaving\" : \"\"}`}\r\n        role=\"alert\"\r\n      >\r\n        <button className=\"close\" onClick={closeAlert} />\r\n        {message}\r\n      </div>\r\n    )\r\n  );\r\n};\r\n\r\nexport default Alert;\r\n", "package.json": "{\n  \"name\": \"stackblitz-starters-rzbtlt\",\n  \"version\": \"0.0.0\",\n  \"private\": true,\n  \"dependencies\": {\n    \"react\": \"18.2.0\",\n    \"react-dom\": \"18.2.0\"\n  },\n  \"scripts\": {\n    \"start\": \"react-scripts start\",\n    \"build\": \"react-scripts build\",\n    \"test\": \"react-scripts test --env=jsdom\",\n    \"eject\": \"react-scripts eject\"\n  },\n  \"devDependencies\": {\n    \"react-scripts\": \"latest\"\n  }\n}", "public/index.html": "<div id=\"app\"></div>", "src/App.js": "import React from ''react'';\nimport Alert from \"../component/Alert\";\nimport \"./style.css\";\n\nexport default function App() {\n  return (\n    <div className=\"App\">\n      <h