 (props) => {\r\n  const [copied, copy] = useCopyToClipboard(\"Lorem ipsum\");\r\n  return (\r\n    <div>\r\n      <button onClick={copy}>Click to copy</button>\r\n      <span>{copied && \"Copied!\"}</span>\r\n    </div>\r\n  );\r\n};\r\n\r\nexport default TextCopy;\r\n", "hook/useCopyToClipboard.js": "import { useState, useEffect, useCallback } from \"react\";\r\n\r\nconst useCopyToClipboard = (text) => {\r\n  const copyToClipboard = (str) => {\r\n    const el = document.createElement(\"textarea\");\r\n    el.value = str;\r\n    el.setAttribute(\"readonly\", \"\");\r\n    el.style.position = \"absolute\";\r\n    el.style.left = \"-9999px\";\r\n    document.body.appendChild(el);\r\n    const selected =\r\n      document.getSelection().rangeCount > 0\r\n        ? document.getSelection().getRangeAt(0)\r\n        : false;\r\n    el.select();\r\n    const success = document.execCommand(\"copy\");\r\n    document.body.removeChild(el);\r\n    if (selected) {\r\n      document.getSelection().removeAllRanges();\r\n      document.getSelection().addRange(selected);\r\n    }\r\n    return success;\r\n  };\r\n\r\n  const [copied, setCopied] = useState(false);\r\n\r\n  const copy = useCallback(() => {\r\n    if (!copied) setCopied(copyToClipboard(text));\r\n  }, [text]);\r\n  useEffect(() => () => setCopied(false), [text]);\r\n\r\n  return [copied, copy];\r\n};\r\n\r\nexport default useCopyToClipboard;\r\n", "package.json": "{\n  \"name\": \"stackblitz-starters-rzbtlt\",\n  \"version\": \"0.0.0\",\n  \"private\": true,\n  \"dependencies\": {\n    \"react\": \"18.2.0\",\n    \"react-dom\": \"18.2.0\"\n  },\n  \"scripts\": {\n    \"start\": \"react-scripts start\",\n    \"build\": \"react-scripts build\",\n    \"test\": \"react-scripts test --env=jsdom\",\n    \"eject\": \"react-scripts eject\"\n  },\n  \"devDependencies\": {\n    \"react-scripts\": \"latest\"\n  }\n}", "public/index.html": "<div id=\"app\"></div>", "src/App.js": "import React from ''react'';\nimport TextCopy from