  }\n}", "public/index.html": "<div id=\"app\"></div>", "src/App.js": "import React from ''react'';\nimport Counter from \"../component/Counter\";\nimport \"./style.css\";\n\nexport default function App() {\n  return (\n    <div className=\"App\">\n      <h1>React useDebounce hook</h1>\n      <Counter />\n    </div>\n  );\n}\n", "src/style.css": "* {\n  box-sizing: border-box;\n}\n\nbody {\n  margin: 0;\n  padding: 1rem;\n  font-family: system-ui, sans-serif;\n  color: black;\n  background-color: white;\n}\n\nh1 {\n  font-weight: 800;\n  font-size: 1.5rem;\n}\n"}', '{"react": "18.2.0", "react-dom": "18.2.0"}', '{"original_path": "component/react/hooks/useDebounce"}'), ('"useDefualt"', '"hooks"', '"react"', '{"component/UserCard.jsx": "import useDefault from \"../hook/useDefault\";\r\n\r\nconst UserCard = () => {\r\n  const [user, setUser] = useDefault({ name: \"Adam\" }, { name: \"John\" });\r\n\r\n  return (\r\n    <>\r\n      <div>User: {user.name}</div>\r\n      <input onChange={(e) => setUser({ name: e.target.value })} />\r\n      <button onClick={() => setUser(null)}>Clear</button>\r\n    </>\r\n  );\r\n};\r\n\r\nexport default UserCard;\r\n", "hook/useDefault.js": "import { useState } from \"react\";\r\n\r\nconst useDefault = (defaultState, initialState) => {\r\n  const [value, setValue] = useState(initialState);\r\n  const isValueEmpty = value === undefined || value === null;\r\n  return [isValueEmpty ? defaultState : value, setValue];\r\n};\r\n\r\nexport default useDefault;\r\n", "package.json": "{\n  \"name\": \"stackblitz-starters-rzbtlt\",\n  \"version\": \"0.0.0\",\n  \"private\": true,\n  \"dependencies\": {\n    \"react\": \"18.2.0\",\n    \"react-dom\": \"18.2.0\"\n  },\n  \"scripts\": {\n    \"start\": \"react-scripts start\",\n    \"build\": \"react-scripts build\",\n    \"test\": \"react-scripts test --env=jsdom\",\n    \"eject\": \"react-scripts eject\"\n  },\n  \"devDependencies\": {\n    \"react-scripts\": \"latest\"\n  }\n}", "public/index.html": "<div id=\"app\"></div>", "src/App.js": "import React from ''react'';\nimport UserCard from \"../component/UserCard\";\nimport \"./style.css\";\n\nexport default function App() {\n  return (\n    <div className=\"App\">\n      <h1>React useDefault hook</h1>\n      <UserCard />\n    </div>\n  );\n}\n", "src/style.css": "* {\n  box-sizing: border-box;\n}\n\nbody {\n  margin: 0;\n  padding: 1rem;\n  font-family: system-ui, sans-serif;\n  color: black;\n  background-color: white;\n}\n\nh1 {\n  font-weight: 800;\n  font-size: 1.5rem;\n}\n"}', '{"react": "18.2.0", "react-dom": "18.2.0"}', '{"original_path": "component/react/hooks/useDefualt"}'), ('"useDelayedState"', '"hooks"', '"react"', '{"hook/useDelayedState.js": "import { useState, useEffect } from \"react\";\r\n\r\nconst useDelayedState = (initialState, condition) => {\r\n  const [{ state, loaded }, setState] = useState({\r\n    state: null,\r\n    loaded: false\r\n  });\r\n\r\n  useEffect(() => {\r\n    if (!loaded && condition) setState({ state: initialState, loaded: true });\r\n  }, [condition, loaded]);\r\n\r\n  const updateState = (newState) => {\r\n    if (!loaded) return;\r\n    setState({ state: newState, loaded });\r\n  };\r\n\r\n  return [state, updateState];\r\n};\r\n\r\nexport default useDelayedState;\r\n", "package.json": "{\n  \"name\": \"stackblitz-starters-rzbtlt\",\n  \"version\": \"0.0.0\",\n  \"private\": true,\n  \"dependencies\": {\n    \"react\": \"18.2.0\",\n    \"react-dom\": \"18.2.0\"\n  },\n  \"scripts\": {\n    \"start\": \"react-scripts start\",\n    \"build\": \"react-scripts build\",\n    \"test\": \"react-scripts test --env=jsdom\",\n    \"eject\": \"react-scripts eject\"\n  },\n  \"devDependencies\": {\n    \"react-scripts\": \"latest\"\n  }\n}", "public/index.html": "<div id=\"app\"></div>", "src/App.js": "import React from ''react'';\nimport { useState, useEffect } from \"react\";\nimport useDelayedState from \"../hook/useDelayedState\";\nimport \"./style.css\";\n\nexport default function App() {\n  const [branches, setBranches] = useState([]);\n  const [selectedBranch, setSelectedBranch] = useDelayedState(\n    branches[0],\n    branches.length\n  );\n\n  useEffect(() => {\n    const handle = setTimeout(() => {\n      setBranches([\"master\", \"staging\", \"test\", \"dev\"]);\n    }, 2000);\n    return () => {\n      handle && clearTimeout(handle);\n    };\n  }, []);\n\n  return (\n    <div className=\"App\">\n      <h1>React useDelayedState hook</h1>\n      <p>Selected branch: {selectedBranch}</p>\n      <select onChange={(e) => setSelectedBranch(e.target.value)}>\n        {branches.map((branch) => (\n          <option key={branch} value={branch}>\n            {branch}\n          </option>\n        ))}\n      </select>\n    </div>\n  );\n}\n", "src/style.css": "* {\n  box-sizing: border-box;\n}\n\nbody {\n  margin: 0;\n  padding: 1rem;\n  font-family: system-ui, sans-serif;\n  color: black;\n  background-color: white;\n}\n\nh1 {\n  font-weight: 800;\n  font-size: 1.5rem;\n}\n"}', '{"react": "18.2.0", "react-dom": "18.2.0"}', '{"original_path": "component/react/hooks/useDelayedState"}'), ('"useEffectOnce"', '"hooks"', '"react"', '{"component/CompName.txt": "", "hook/useEffectOnce.js": "import { useEffect, useRef } from \"react\";\r\n\r\nconst useEffectOnce = (callback, when) => {\r\n  const hasRunOnce = useRef(false);\r\n  useEffect(() => {\r\n    if (when && !hasRunOnce.current) {\r\n      callback();\r\n      hasRunOnce.current = true;\r\n    }\r\n  }, [when]);\r\n};\r\n\r\nexport default useEffectOnce;\r\n", "package.json": "{\n  \"name\": \"stackblitz-starters-rzbtlt\",\n  \"version\": \"0.0.0\",\n  \"private\": true,\n  \"dependencies\": {\n    \"react\": \"18.2.0\",\n    \"react-dom\": \"18.2.0\"\n  },\n  \"scripts\": {\n    \"start\": \"react-scripts start\",\n    \"build\": \"react-scripts build\",\n    \"test\": \"react-scripts test --env=jsdom\",\n    \"eject\": \"react-scripts eject\"\n  },\n  \"devDependencies\": {\n    \"react-scripts\": \"latest\"\n  }\n}", "public/index.html": "<div id=\"app\"></div>", "src/App.js": "import React from ''react'';\nimport { useState } from \"react\";\nimport useEffectOnce from \"../hook/useEffectonce\";\nimport \"./style.css\";\n\nexport default function App() {\n  const [clicked, setClicked] = useState(false);\n  useEffectOnce(() => {\n    console.log(\"mounted\");\n  }, clicked);\n\n  return (\n    <div className=\"App\">\n      <h1>React useEffectOnce hook</h1>\n      <button onClick={() => setClicked(true)}>Click me</button>\n    </div>\n  );\n}\n", "src/style.css": "* {\n  box-sizing: border-box;\n}\n\nbody {\n  margin: 0;\n  padding: 1rem;\n  font-family: system-ui, sans-serif;\n  color: black;\n  background-color: white;\n}\n\nh1 {\n  font-weight: 800;\n  font-size: 1.5rem;\n}\n"}', '{"react": "18.2.0", "react-dom": "18.2.0"}', '{"original_path": "component/react/hooks/useEffectOnce"}');